280	static void InsertByPriority(vector<of<Dependency>>& list,
281	                             const an<Dependency>& value) {
282	  auto upper = std::upper_bound(
283	      list.begin(), list.end(), value,
284	      [](const an<Dependency>& lhs, const an<Dependency>& rhs) {
285	        return lhs->priority() < rhs->priority();
286	      });
287	  list.insert(upper, value);
288	}
