475	static an<ConfigItem> ResolveReference(ConfigCompiler* compiler,
476	                                       const Reference& reference) {
477	  auto resource = compiler->GetCompiledResource(reference.resource_id);
478	  if (!resource) {
479	    DLOG(INFO) << "resource not loaded, compiling: " << reference.resource_id;
480	    resource = compiler->Compile(reference.resource_id);
481	    if (!resource->loaded) {
482	      if (reference.optional) {
483	        LOG(INFO) << "optional resource not loaded: " << reference.resource_id;
484	      } else {
485	        LOG(ERROR) << "resource could not be loaded: " << reference.resource_id;
486	      }
487	      return nullptr;
488	    }
489	  }
490	  return GetResolvedItem(compiler, resource, reference.local_path);
