496	static bool ParseInclude(ConfigCompiler* compiler, const an<ConfigItem>& item) {
497	  if (Is<ConfigValue>(item)) {
498	    auto path = As<ConfigValue>(item)->str();
499	    DLOG(INFO) << "ParseInclude(" << path << ")";
