525	// Modifies subnodes or list elements at specified paths.
526	// __patch: path/to/node
527	// __patch: filename[.yaml]:/path/to/node
528	// __patch: { key/alpha: value, key/beta: value }
529	static bool ParsePatch(ConfigCompiler* compiler, const an<ConfigItem>& item) {
530	  if (Is<ConfigValue>(item)) {
531	    auto path = As<ConfigValue>(item)->str();
532	    DLOG(INFO) << "ParsePatch(" << path << ")";
533	    compiler->AddDependency(
534	        New<PatchReference>(compiler->CreateReference(path)));
535	    return true;
536	  }
537	  if (Is<ConfigMap>(item)) {
538	    DLOG(INFO) << "ParsePatch(<literal>)";
539	    compiler->AddDependency(New<PatchLiteral>(As<ConfigMap>(item)));
540	    return true;
541	  }
542	  return false;
543	}
