567	static bool HasCircularDependencies(ConfigDependencyGraph* graph,
568	                                    const string& path) {
569	  for (const auto& x : graph->resolve_chain) {
570	    if (boost::starts_with(x, path) &&
571	        (x.length() == path.length() || x[path.length()] == '/'))
572	      return true;
573	  }
574	  return false;
575	}
576	
577	bool ConfigCompiler::ResolveDependencies(const string& path) {
578	  DLOG(INFO) << "ResolveDependencies(" << path << ")";
579	  auto found = graph_->deps.find(path);
580	  if (found == graph_->deps.end()) {
581	    return true;
582	  }
583	  if (HasCircularDependencies(graph_.get(), path)) {
584	    LOG(WARNING) << "circular dependencies detected in " << path;
585	    return false;
586	  }
587	  graph_->resolve_chain.push_back(path);
588	  auto& deps = found->second;
589	  for (auto iter = deps.begin(); iter != deps.end();) {
590	    if (!(*iter)->Resolve(this)) {
591	      LOG(ERROR) << "unresolved dependency: " << **iter;
592	      return false;
593	    }
594	    LOG(INFO) << "resolved: " << **iter;
595	    iter = deps.erase(iter);
596	  }
597	  graph_->resolve_chain.pop_back();
598	  DLOG(INFO) << "all dependencies resolved.";
599	  return true;
600	}
