181	an<ConfigItemRef> TraverseCopyOnWrite(an<ConfigItemRef> head,
182	                                      const string& node_path) {
183	  DLOG(INFO) << "TraverseCopyOnWrite(" << node_path << ")";
184	  if (node_path.empty() || node_path == "/") {
185	    return head;
186	  }
187	  vector<string> keys = ConfigData::SplitPath(node_path);
188	  size_t n = keys.size();
189	  for (size_t i = 0; i < n; ++i) {
190	    const auto& key = keys[i];
191	    if (auto child = TypeCheckedCopyOnWrite(head, key)) {
192	      head = child;
193	    } else {
194	      LOG(ERROR) << "while writing to " << node_path;
195	      return nullptr;
196	    }
197	  }
198	  return head;
199	}
